declare(strict_types=1);require_once dirname(__DIR__).'/includes/cms.php';require_once dirname(__DIR__,3).'/includes/dte.php';require_once dirname(__DIR__,3).'/includes/notificaciones.php';require_once dirname(__DIR__,3).'/includes/errores_sistema.php';require_once dirname(__DIR__,3).'/includes/audit.php';exigirPermiso('dte.manage');$id=cmsId($_POST['id']??0);$accion=(string)($_POST['accion']??'');$motivo=trim((string)($_POST['motivo']??''));if(($_SERVER['REQUEST_METHOD']??'')!=='POST'||!validarTokenCsrf((string)($_POST['csrf_token']??''))||!in_array($accion,['consultar','invalidar'],true)||($accion==='invalidar'&&($motivo===''||mb_strlen($motivo)>500))){cmsFlash('error','Solicitud inválida; el motivo es obligatorio para invalidar.');header('Location:index.php');exit;}$pdo=obtenerConexion();$q=$pdo->prepare('SELECT * FROM dte_documentos WHERE id=:id');$q->execute(['id'=>$id]);$d=$q->fetch();if(!$d){cmsFlash('error','DTE no encontrado.');header('Location:index.php');exit;}try{$c=configuracionDte($pdo);if($c['ambiente']!==$d['ambiente'])throw new RuntimeException('El ambiente activo no coincide con el documento.');$provider=proveedorDte($c);$doc=json_decode($d['json_documento'],true,512,JSON_THROW_ON_ERROR);$r=$accion==='consultar'?$provider->queryStatus($d['codigo_generacion'],$c):$provider->invalidate($doc,$motivo,$c);$estado=mb_substr((string)($r['estado']??strtoupper($accion)),0,40);$pdo->beginTransaction();$pdo->prepare('INSERT INTO dte_eventos(dte_id,pedido_id,operacion,ambiente,resultado,response_sanitizado,codigo,observaciones) VALUES(:d,:p,:o,:a,\'success\',:r,:c,:n)')->execute(['d'=>$id,'p'=>$d['pedido_id'],'o'=>$accion,'a'=>$d['ambiente'],'r'=>json_encode(sanitizarContextoErrorAtenea($r),JSON_UNESCAPED_UNICODE|JSON_THROW_ON_ERROR),'c'=>$estado,'n'=>$motivo?:null]);if($accion==='invalidar')$pdo->prepare('UPDATE dte_documentos SET estado=:e,observaciones=:o WHERE id=:id')->execute(['e'=>$estado,'o'=>$motivo,'id'=>$id]);registrarAuditoria(['actor_user_id'=>$_SESSION['usuario_id'],'event_type'=>'dte.'.$accion,'module'=>'dte','entity_type'=>'dte','entity_id'=>$id,'action'=>$accion,'result'=>'success','description'=>'Operación DTE ejecutada mediante el provider configurado.'], $pdo);$pdo->commit();cmsFlash('exito','Operación DTE completada mediante el provider.');}catch(Throwable $e){if($pdo->inTransaction())$pdo->rollBack();registrarErrorSistemaAtenea('dte','dte_provider',$e->getMessage(),['pedido_id'=>$d['pedido_id'],'dte_id'=>$id]);cmsFlash('error','La operación DTE falló. El detalle sanitizado quedó registrado.');}header('Location:detalle.php?id='.$id);
